INSERT INTO question_content (module_type, question_type, stem, options_json, correct_answer, explanation, level, difficulty, review_status, publish_status)
VALUES
    ('level_test', 'single_choice', 'Which phrase is most appropriate to open a formal business email?', '["Hi buddy", "Dear Mr. Chen", "Yo Chen", "Hey there"]'::jsonb, 'Dear Mr. Chen', 'Formal business emails usually start with a professional salutation.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'Choose the best response in a meeting: "Could you clarify the timeline?"', '["Yes, I timeline", "Sure, we expect delivery next Friday", "Timeline is good", "No comment"]'::jsonb, 'Sure, we expect delivery next Friday', 'The best answer directly clarifies the schedule.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'What does "follow up" most likely mean in business English?', '["Cancel a task", "Check progress later", "Sign a contract", "Take a vacation"]'::jsonb, 'Check progress later', 'Follow up means checking progress after an earlier action.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'Choose the most suitable phrase for negotiation.', '["Take it or leave it", "Let us explore a win-win solution", "I do not care", "Whatever"]'::jsonb, 'Let us explore a win-win solution', 'Negotiation language should be cooperative and professional.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which sentence is best for a presentation transition?', '["Anyway, next", "Moving on to the next point", "Stop here", "You know"]'::jsonb, 'Moving on to the next point', 'It is the clearest and most professional transition.', 'BEC Vantage', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which option best expresses a polite disagreement?', '["You are wrong", "I see your point, but I have a different view", "No", "Impossible"]'::jsonb, 'I see your point, but I have a different view', 'Polite disagreement is important in business settings.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'What is the best phrase for confirming understanding?', '["Got it", "If I understand correctly, the shipment leaves on Monday", "Fine", "Okay maybe"]'::jsonb, 'If I understand correctly, the shipment leaves on Monday', 'This phrase is explicit and professional.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Choose the best phrase to close a meeting.', '["Bye", "Let us summarize the action items", "Enough", "End now"]'::jsonb, 'Let us summarize the action items', 'Summarizing action items is a strong business habit.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which sentence sounds most professional in a delay notice?', '["We are late, sorry", "We regret the delay and are taking steps to resolve it", "Delay happened", "Not our problem"]'::jsonb, 'We regret the delay and are taking steps to resolve it', 'Professional delay notices acknowledge the issue and show action.', 'BEC Higher', 'hard', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which phrase best invites questions after a presentation?', '["Any issues?", "I would be happy to take your questions", "No questions", "Finished"]'::jsonb, 'I would be happy to take your questions', 'This is polite and natural in presentations.', 'BEC Vantage', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which email closing is most appropriate when you promise future help?', '["Thanks!", "Thank you for your support and please let me know if you need anything else.", "Thx buddy", "Bye"]'::jsonb, 'Thank you for your support and please let me know if you need anything else.', 'A complete closing sentence keeps a formal and helpful tone.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'What does ''circle back'' usually mean in business English?', '["Ignore someone", "Return to the topic later", "Schedule a party", "Cancel the plan"]'::jsonb, 'Return to the topic later', '''Circle back'' signals revisiting an item after gathering more info.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'Choose the best phrase for arranging a short sync call.', '["Give me your time", "Could we have a quick sync at 3 p.m. tomorrow?", "Call me now", "Need meeting"]'::jsonb, 'Could we have a quick sync at 3 p.m. tomorrow?', 'It clearly proposes a polite meeting time.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which sentence best acknowledges a colleague''s idea?', '["Whatever", "That makes sense, and we could also explore option B", "Next", "Stop"]'::jsonb, 'That makes sense, and we could also explore option B', 'It validates the idea and adds constructive input.', 'BEC Preliminary', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Select the clearest reminder for unpaid invoices.', '["Pay now", "This is a friendly reminder that invoice #248 is due on Friday.", "Money please", "Hurry up"]'::jsonb, 'This is a friendly reminder that invoice #248 is due on Friday.', 'It references the invoice and keeps a professional tone.', 'BEC Preliminary', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which phrase best escalates an issue politely?', '["I already told you", "May I escalate this to our director so we can unblock the shipment?", "Handle it", "This is not my job"]'::jsonb, 'May I escalate this to our director so we can unblock the shipment?', 'It states the intention and the business reason.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Choose the best transition for a status presentation.', '["Whatever, next", "Now let us move to the risk mitigation plan", "Skip it", "Done"]'::jsonb, 'Now let us move to the risk mitigation plan', 'A clear transition keeps listeners oriented.', 'BEC Vantage', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'What is the most diplomatic way to challenge a budget cut?', '["You cannot", "Could we review the impact on client commitments before finalizing the cut?", "This is nonsense", "Forget it"]'::jsonb, 'Could we review the impact on client commitments before finalizing the cut?', 'It questions the change while focusing on business outcomes.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Select the strongest phrase for summarizing next steps in a meeting.', '["All good", "To summarize, marketing will deliver the draft by Tuesday and finance will confirm the budget.", "That is it", "Okay"]'::jsonb, 'To summarize, marketing will deliver the draft by Tuesday and finance will confirm the budget.', 'It clearly assigns owners and deadlines.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which sentence best requests clarification on a KPI?', '["Explain", "Could you clarify whether the KPI is measured weekly or monthly?", "Why", "Tell"]'::jsonb, 'Could you clarify whether the KPI is measured weekly or monthly?', 'It specifies what needs clarification.', 'BEC Vantage', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'How should you highlight a strategic risk in an executive review?', '["We may fail", "There is a high probability that supply delays will impact Q3 revenue unless we confirm a secondary vendor.", "Maybe bad", "It is risky"]'::jsonb, 'There is a high probability that supply delays will impact Q3 revenue unless we confirm a secondary vendor.', 'It quantifies the risk and proposes mitigation.', 'BEC Higher', 'hard', 'approved', 'published'),
    ('level_test', 'single_choice', 'Choose the best statement for aligning global stakeholders.', '["Do what I said", "Let us align with both APAC and EMEA teams so the pricing narrative stays consistent across regions.", "Follow me", "Just copy"]'::jsonb, 'Let us align with both APAC and EMEA teams so the pricing narrative stays consistent across regions.', 'It specifies whom to align and why.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which option demonstrates effective executive persuasion?', '["You must approve", "Approving the additional headcount will shorten onboarding by two weeks and protect the go-live date.", "No choice", "Trust me"]'::jsonb, 'Approving the additional headcount will shorten onboarding by two weeks and protect the go-live date.', 'It connects the request to measurable business impact.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Select the most persuasive response to a client''s quality concern.', '["Relax", "We have added an extra QA gate so your shipment meets every compliance requirement.", "Do not worry", "Later"]'::jsonb, 'We have added an extra QA gate so your shipment meets every compliance requirement.', 'It shows a concrete action tied to the client''s worry.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which phrase best asks for a strategic decision timeline?', '["Decide now", "Could you let us know the decision timeline so we can reserve production capacity?", "Tell me", "Time please"]'::jsonb, 'Could you let us know the decision timeline so we can reserve production capacity?', 'It links the decision timing to a business dependency.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which sentence best asks a colleague to send the meeting attachments?', '["Give files", "Could you please forward the deck and notes after the call?", "Files now", "Send it"]'::jsonb, 'Could you please forward the deck and notes after the call?', 'It is a polite and specific follow-up request.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'Choose the best phrase to confirm understanding of action items.', '["Ok", "Just to confirm, I will share the draft and you will review it by Thursday, correct?", "Fine", "Sure"]'::jsonb, 'Just to confirm, I will share the draft and you will review it by Thursday, correct?', 'It restates owners and deadline clearly.', 'BEC Preliminary', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which expression politely requests meeting minutes?', '["Send minutes", "Would you mind sharing the meeting minutes once they are ready?", "We need it", "Do it"]'::jsonb, 'Would you mind sharing the meeting minutes once they are ready?', 'It is polite and gives context.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'What is the most professional way to acknowledge a delay?', '["We are late", "We apologize for the delay and have added extra staff to recover the timeline.", "Sorry", "Deal with it"]'::jsonb, 'We apologize for the delay and have added extra staff to recover the timeline.', 'It acknowledges responsibility and shares a solution.', 'BEC Preliminary', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which phrase best requests an updated forecast?', '["Tell future", "Could you share the revised sales forecast before Friday''s leadership call?", "Forecast now", "Update soon"]'::jsonb, 'Could you share the revised sales forecast before Friday''s leadership call?', 'It is precise about the deliverable and deadline.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'How should you highlight a dependency risk to partners?', '["Risk big", "Our launch depends on your API by 5 May; without it the training sequence slips two weeks.", "Be careful", "Need API"]'::jsonb, 'Our launch depends on your API by 5 May; without it the training sequence slips two weeks.', 'It quantifies impact and names the dependency.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Choose the best statement to secure resources from leadership.', '["Give us budget", "Approving two additional engineers now keeps the regulatory deadline on track and avoids penalty fees.", "Need people", "Send staff"]'::jsonb, 'Approving two additional engineers now keeps the regulatory deadline on track and avoids penalty fees.', 'It ties the request to measurable business impact.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which sentence best frames ROI in an executive summary?', '["ROI is ok", "This project delivers a 4x ROI within 12 months by reducing manual onboarding cost by $1.2M.", "Profit soon", "Money good"]'::jsonb, 'This project delivers a 4x ROI within 12 months by reducing manual onboarding cost by $1.2M.', 'It quantifies value and timing.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'How do you request compliance documentation from a vendor?', '["Send docs", "Could you provide the latest SOC 2 certificate so our audit team can finalize approval?", "Need proof", "Compliance now"]'::jsonb, 'Could you provide the latest SOC 2 certificate so our audit team can finalize approval?', 'It states exactly what is needed and why.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which statement is best when offering service credits in a negotiation?', '["Take discount", "If we provide two months of service credits, could you commit to the three-year renewal?", "Free service", "We pay"]'::jsonb, 'If we provide two months of service credits, could you commit to the three-year renewal?', 'It frames the concession as a trade-off.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which sentence summarizes cross-team dependencies most clearly?', '["Teams must help", "Legal must finalize the contract draft by Monday so procurement can issue the PO on Wednesday.", "Do everything", "We all know"]'::jsonb, 'Legal must finalize the contract draft by Monday so procurement can issue the PO on Wednesday.', 'It names owners and dates.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which option best escalates a customer risk to the GM?', '["Customer angry", "Our top-three customer is threatening to pause orders unless we guarantee the quality audit this Friday.", "Need help", "Fix it"]'::jsonb, 'Our top-three customer is threatening to pause orders unless we guarantee the quality audit this Friday.', 'It qualifies the risk and urgency.', 'BEC Higher', 'hard', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which sentence best summarizes KPI trends for executives?', '[{"label": "KPIs are fine.", "value": "KPIs are fine."}, {"label": "Revenue is 6% ahead of plan while churn rose two points in APAC; we are launching a retention playbook this month.", "value": "Revenue is 6% ahead of plan while churn rose two points in APAC; we are launching a retention playbook this month."}, {"label": "Numbers changed.", "value": "Numbers changed."}, {"label": "All good maybe.", "value": "All good maybe."}]'::jsonb, 'Revenue is 6% ahead of plan while churn rose two points in APAC; we are launching a retention playbook this month.', 'Leadership updates pair metrics with actions.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Choose the most precise status update for an OKR.', '[{"label": "Progressing.", "value": "Progressing."}, {"label": "Objective 2 is at 70%: onboarding automation is live for 120 dealers and cutting manual hours by 40%.", "value": "Objective 2 is at 70%: onboarding automation is live for 120 dealers and cutting manual hours by 40%."}, {"label": "Going well.", "value": "Going well."}, {"label": "Still working.", "value": "Still working."}]'::jsonb, 'Objective 2 is at 70%: onboarding automation is live for 120 dealers and cutting manual hours by 40%.', 'Quantifying progress and impact builds credibility.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which statement frames a risk with mitigation clearly?', '[{"label": "Risk exists.", "value": "Risk exists."}, {"label": "Supplier tooling is two weeks late; we secured a backup vendor and expect zero impact on launch if we ship CAD files by Monday.", "value": "Supplier tooling is two weeks late; we secured a backup vendor and expect zero impact on launch if we ship CAD files by Monday."}, {"label": "Problem maybe.", "value": "Problem maybe."}, {"label": "It''s bad.", "value": "It''s bad."}]'::jsonb, 'Supplier tooling is two weeks late; we secured a backup vendor and expect zero impact on launch if we ship CAD files by Monday.', 'Executives want both the issue and the mitigation plan.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Identify the best way to highlight customer impact in a report.', '[{"label": "Customers like it.", "value": "Customers like it."}, {"label": "NPS climbed from 34 to 52 after we launched proactive onboarding check-ins; the same play will roll out to enterprise clients next.", "value": "NPS climbed from 34 to 52 after we launched proactive onboarding check-ins; the same play will roll out to enterprise clients next."}, {"label": "More satisfied.", "value": "More satisfied."}, {"label": "Users happier.", "value": "Users happier."}]'::jsonb, 'NPS climbed from 34 to 52 after we launched proactive onboarding check-ins; the same play will roll out to enterprise clients next.', 'Use before/after metrics and explain the next experiment.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which line best introduces a board slide on investment needs?', '[{"label": "Need money.", "value": "Need money."}, {"label": "To hit the automation roadmap, we request $2.3M for tooling and data hires, yielding $6M in annual savings by FY27.", "value": "To hit the automation roadmap, we request $2.3M for tooling and data hires, yielding $6M in annual savings by FY27."}, {"label": "Budget please.", "value": "Budget please."}, {"label": "Give more.", "value": "Give more."}]'::jsonb, 'To hit the automation roadmap, we request $2.3M for tooling and data hires, yielding $6M in annual savings by FY27.', 'Investment asks must tie spend to return.', 'BEC Higher', 'hard', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which sentence clarifies variance drivers in a flash report?', '[{"label": "Costs up.", "value": "Costs up."}, {"label": "Operating expenses exceeded plan by $180k due to the accelerated APAC launch; offsetting savings will appear next quarter.", "value": "Operating expenses exceeded plan by $180k due to the accelerated APAC launch; offsetting savings will appear next quarter."}, {"label": "Budget overspent.", "value": "Budget overspent."}, {"label": "Spent too much.", "value": "Spent too much."}]'::jsonb, 'Operating expenses exceeded plan by $180k due to the accelerated APAC launch; offsetting savings will appear next quarter.', 'Explain cause and forward-looking impact together.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which phrase requests executive support diplomatically?', '[{"label": "Help.", "value": "Help."}, {"label": "Could you sponsor the security review so infra prioritizes it this sprint? We''ll be blocked until then.", "value": "Could you sponsor the security review so infra prioritizes it this sprint? We''ll be blocked until then."}, {"label": "Need you.", "value": "Need you."}, {"label": "Do something.", "value": "Do something."}]'::jsonb, 'Could you sponsor the security review so infra prioritizes it this sprint? We''ll be blocked until then.', 'Be specific about the ask and the consequence.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which sentence frames a course correction tactfully?', '[{"label": "We failed.", "value": "We failed."}, {"label": "Given the lower conversion from webinars, we are reallocating $300k to partner-driven demos for the remainder of the year.", "value": "Given the lower conversion from webinars, we are reallocating $300k to partner-driven demos for the remainder of the year."}, {"label": "Change plan.", "value": "Change plan."}, {"label": "Switch strategy.", "value": "Switch strategy."}]'::jsonb, 'Given the lower conversion from webinars, we are reallocating $300k to partner-driven demos for the remainder of the year.', 'Tie the change to data and specify the new action.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which question invites senior feedback on a tough trade-off?', '[{"label": "What now?", "value": "What now?"}, {"label": "Do you prefer we protect gross margin by delaying the LATAM launch or accept a short-term hit to accelerate market share?", "value": "Do you prefer we protect gross margin by delaying the LATAM launch or accept a short-term hit to accelerate market share?"}, {"label": "Tell us.", "value": "Tell us."}, {"label": "Need advice.", "value": "Need advice."}]'::jsonb, 'Do you prefer we protect gross margin by delaying the LATAM launch or accept a short-term hit to accelerate market share?', 'Executives respond better to clearly framed options.', 'BEC Higher', 'hard', 'approved', 'published'),
    ('level_test', 'single_choice', 'Select the most concise progress highlight for a dashboard.', '[{"label": "Deployment complete.", "value": "Deployment complete."}, {"label": "Automation bot is live in all hubs, removing 4,000 manual tickets per month.", "value": "Automation bot is live in all hubs, removing 4,000 manual tickets per month."}, {"label": "It works.", "value": "It works."}, {"label": "All set.", "value": "All set."}]'::jsonb, 'Automation bot is live in all hubs, removing 4,000 manual tickets per month.', 'Headlines should combine milestone + quantified benefit.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which line introduces a sensitive people topic professionally?', '[{"label": "People issue.", "value": "People issue."}, {"label": "To address rising attrition in engineering, we''re launching a retention plan focused on technical mentorship and compensation benchmarking.", "value": "To address rising attrition in engineering, we''re launching a retention plan focused on technical mentorship and compensation benchmarking."}, {"label": "Staff unhappy.", "value": "Staff unhappy."}, {"label": "Morale low.", "value": "Morale low."}]'::jsonb, 'To address rising attrition in engineering, we''re launching a retention plan focused on technical mentorship and compensation benchmarking.', 'Describe the issue plus the structured response.', 'BEC Higher', 'hard', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which email opening is most suitable when writing to a new supplier contact?', '[{"label": "Dear Ms. Patel, I hope this message finds you well.", "value": "Dear Ms. Patel, I hope this message finds you well."}, {"label": "Hey there, long time no see!", "value": "Hey there, long time no see!"}, {"label": "Yo!", "value": "Yo!"}, {"label": "Sup?", "value": "Sup?"}]'::jsonb, 'Dear Ms. Patel, I hope this message finds you well.', 'Formal greetings with the recipient''s surname are expected in first-contact business emails.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'Choose the best sentence to acknowledge receipt of a quotation.', '[{"label": "Got it.", "value": "Got it."}, {"label": "We confirm receipt of your quotation and will review it this afternoon.", "value": "We confirm receipt of your quotation and will review it this afternoon."}, {"label": "Send again later.", "value": "Send again later."}, {"label": "Message received maybe.", "value": "Message received maybe."}]'::jsonb, 'We confirm receipt of your quotation and will review it this afternoon.', 'Clear acknowledgement plus next step helps maintain professional tone.', 'BEC Preliminary', 'easy', 'approved', 'published')
INSERT INTO question_content (module_type, question_type, stem, options_json, correct_answer, explanation, level, difficulty, review_status, publish_status)
VALUES
    ('level_test', 'single_choice', 'Which closing line maintains a helpful tone after supporting a client?', '[{"label": "Let me know if you need anything else and thank you for your partnership.", "value": "Let me know if you need anything else and thank you for your partnership."}, {"label": "That is all.", "value": "That is all."}, {"label": "Bye.", "value": "Bye."}, {"label": "Stop emailing me.", "value": "Stop emailing me."}]'::jsonb, 'Let me know if you need anything else and thank you for your partnership.', 'Closing with appreciation and support is standard for client-facing BEC communication.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'What is the most polite way to request missing attachments?', '[{"label": "Why did you forget the files?", "value": "Why did you forget the files?"}, {"label": "Could you please resend the deck and budget attachments at your convenience?", "value": "Could you please resend the deck and budget attachments at your convenience?"}, {"label": "Need files now.", "value": "Need files now."}, {"label": "Send attachments ASAP or else.", "value": "Send attachments ASAP or else."}]'::jsonb, 'Could you please resend the deck and budget attachments at your convenience?', 'Polite phrasing plus clear reference to the items keeps the request professional.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'Select the clearest reminder for an upcoming payment deadline.', '[{"label": "Invoice soon.", "value": "Invoice soon."}, {"label": "This is a friendly reminder that invoice DH-2045 is due on 18 April.", "value": "This is a friendly reminder that invoice DH-2045 is due on 18 April."}, {"label": "Money time.", "value": "Money time."}, {"label": "Where is payment?", "value": "Where is payment?"}]'::jsonb, 'This is a friendly reminder that invoice DH-2045 is due on 18 April.', 'Referencing the invoice number and date reduces ambiguity.', 'BEC Preliminary', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which phrase best introduces the purpose of an email to a new stakeholder?', '[{"label": "Here comes information.", "value": "Here comes information."}, {"label": "I am reaching out to share the updated project milestones for your review.", "value": "I am reaching out to share the updated project milestones for your review."}, {"label": "Guess what?", "value": "Guess what?"}, {"label": "Need to talk.", "value": "Need to talk."}]'::jsonb, 'I am reaching out to share the updated project milestones for your review.', 'Explicitly stating the reason early helps busy readers.', 'BEC Preliminary', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Identify the most professional way to thank someone for rapid feedback.', '[{"label": "Cheers.", "value": "Cheers."}, {"label": "Thanks for the quick turnaround—this helps us finalize the launch plan on schedule.", "value": "Thanks for the quick turnaround—this helps us finalize the launch plan on schedule."}, {"label": "Cool.", "value": "Cool."}, {"label": "Nice one.", "value": "Nice one."}]'::jsonb, 'Thanks for the quick turnaround—this helps us finalize the launch plan on schedule.', 'Linking appreciation to business impact shows respect for the effort.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which sentence politely follows up on an unanswered email?', '[{"label": "You ignored me.", "value": "You ignored me."}, {"label": "Just checking whether you had a chance to review the partnership proposal below.", "value": "Just checking whether you had a chance to review the partnership proposal below."}, {"label": "Hey?", "value": "Hey?"}, {"label": "Are you there?", "value": "Are you there?"}]'::jsonb, 'Just checking whether you had a chance to review the partnership proposal below.', 'Polite follow-ups restate the pending item instead of blaming the reader.', 'BEC Preliminary', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Choose the best sentence to provide context when forwarding minutes to a manager.', '[{"label": "FYI.", "value": "FYI."}, {"label": "Please find attached the supplier workshop minutes; action items relevant to finance are highlighted.", "value": "Please find attached the supplier workshop minutes; action items relevant to finance are highlighted."}, {"label": "Look.", "value": "Look."}, {"label": "See attached maybe.", "value": "See attached maybe."}]'::jsonb, 'Please find attached the supplier workshop minutes; action items relevant to finance are highlighted.', 'Summaries plus a callout of relevance respect the reader''s time.', 'BEC Preliminary', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which statement best communicates that a file was updated?', '[{"label": "Changed it.", "value": "Changed it."}, {"label": "I have updated the forecast worksheet with the latest Q2 run rate; please review tab 3.", "value": "I have updated the forecast worksheet with the latest Q2 run rate; please review tab 3."}, {"label": "Fixed now.", "value": "Fixed now."}, {"label": "Version new.", "value": "Version new."}]'::jsonb, 'I have updated the forecast worksheet with the latest Q2 run rate; please review tab 3.', 'Mentioning the change and where to look prevents confusion.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'What is the clearest way to confirm meeting attendance?', '[{"label": "OK.", "value": "OK."}, {"label": "Confirming that I will join the pricing review on Tuesday at 15:00.", "value": "Confirming that I will join the pricing review on Tuesday at 15:00."}, {"label": "Sure maybe.", "value": "Sure maybe."}, {"label": "See you?", "value": "See you?"}]'::jsonb, 'Confirming that I will join the pricing review on Tuesday at 15:00.', 'Include meeting name and time when acknowledging attendance.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which sentence keeps a professional tone while declining a meeting?', '[{"label": "Busy, sorry.", "value": "Busy, sorry."}, {"label": "I am afraid I have a client briefing at that time—could we move the sync to Thursday morning?", "value": "I am afraid I have a client briefing at that time—could we move the sync to Thursday morning?"}, {"label": "Nope.", "value": "Nope."}, {"label": "Cannot.", "value": "Cannot."}]'::jsonb, 'I am afraid I have a client briefing at that time—could we move the sync to Thursday morning?', 'Declines should provide a reason and alternative whenever possible.', 'BEC Preliminary', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Select the most appropriate email subject for a contract review.', '[{"label": "Hello", "value": "Hello"}, {"label": "Action required: review draft master services agreement by Friday", "value": "Action required: review draft master services agreement by Friday"}, {"label": "Contract", "value": "Contract"}, {"label": "Read this", "value": "Read this"}]'::jsonb, 'Action required: review draft master services agreement by Friday', 'Effective subjects summarize the request and deadline.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which response offers help to a coworker who flagged workload issues?', '[{"label": "Not my problem.", "value": "Not my problem."}, {"label": "Let me know which sections I can draft so we split the workload evenly.", "value": "Let me know which sections I can draft so we split the workload evenly."}, {"label": "Figure it out.", "value": "Figure it out."}, {"label": "Too busy.", "value": "Too busy."}]'::jsonb, 'Let me know which sections I can draft so we split the workload evenly.', 'Collaborative tone is key in BEC tasks that value teamwork.', 'BEC Preliminary', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Identify the safest way to share a revised policy document.', '[{"label": "Sending policy.", "value": "Sending policy."}, {"label": "Attached is the updated travel policy; please note the highlighted approvals section on page 3.", "value": "Attached is the updated travel policy; please note the highlighted approvals section on page 3."}, {"label": "New doc.", "value": "New doc."}, {"label": "Policy changed lol.", "value": "Policy changed lol."}]'::jsonb, 'Attached is the updated travel policy; please note the highlighted approvals section on page 3.', 'Providing context and pointing to key changes helps adoption.', 'BEC Preliminary', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which sentence best opens a virtual status meeting?', '[{"label": "Let''s go.", "value": "Let''s go."}, {"label": "Thanks for joining—today we will review the sprint burn-down and unblock the payment integration issues.", "value": "Thanks for joining—today we will review the sprint burn-down and unblock the payment integration issues."}, {"label": "Any questions?", "value": "Any questions?"}, {"label": "So...", "value": "So..."}]'::jsonb, 'Thanks for joining—today we will review the sprint burn-down and unblock the payment integration issues.', 'Leaders should state agenda and purpose right away.', 'BEC Vantage', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'Choose the best way to invite questions after presenting data.', '[{"label": "Done.", "value": "Done."}, {"label": "Happy to take any questions about the assumptions or next steps.", "value": "Happy to take any questions about the assumptions or next steps."}, {"label": "No questions.", "value": "No questions."}, {"label": "Figure it out.", "value": "Figure it out."}]'::jsonb, 'Happy to take any questions about the assumptions or next steps.', 'Inviting discussion explicitly encourages engagement.', 'BEC Vantage', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which phrase keeps the meeting on schedule when discussion drifts?', '[{"label": "Stop talking.", "value": "Stop talking."}, {"label": "Let''s capture that off-line so we can finish the risk review within the remaining ten minutes.", "value": "Let''s capture that off-line so we can finish the risk review within the remaining ten minutes."}, {"label": "Whatever.", "value": "Whatever."}, {"label": "Move on.", "value": "Move on."}]'::jsonb, 'Let''s capture that off-line so we can finish the risk review within the remaining ten minutes.', 'Acknowledge the idea but refocus on the agenda and time box.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Identify the best way to summarize decisions at the end of a stand-up.', '[{"label": "Good job.", "value": "Good job."}, {"label": "To recap: product will deliver the demo build by Monday, CX will draft the comms, and finance will confirm pricing approvals.", "value": "To recap: product will deliver the demo build by Monday, CX will draft the comms, and finance will confirm pricing approvals."}, {"label": "Same thing tomorrow.", "value": "Same thing tomorrow."}, {"label": "See ya.", "value": "See ya."}]'::jsonb, 'To recap: product will deliver the demo build by Monday, CX will draft the comms, and finance will confirm pricing approvals.', 'Summaries should pair owners with actions and deadlines.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which question politely checks whether everyone supports a proposal?', '[{"label": "Any objections?", "value": "Any objections?"}, {"label": "Does anyone foresee risks if we move forward with the phased launch plan next quarter?", "value": "Does anyone foresee risks if we move forward with the phased launch plan next quarter?"}, {"label": "Speak now.", "value": "Speak now."}, {"label": "All good, right?", "value": "All good, right?"}]'::jsonb, 'Does anyone foresee risks if we move forward with the phased launch plan next quarter?', 'Specific prompts elicit thoughtful feedback instead of silence.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Select the best sentence to encourage quieter participants to share.', '[{"label": "Anyone else?", "value": "Anyone else?"}, {"label": "Emily, you led the client interviews—would you share your view before we decide?", "value": "Emily, you led the client interviews—would you share your view before we decide?"}, {"label": "Speak louder.", "value": "Speak louder."}, {"label": "We don''t have time.", "value": "We don''t have time."}]'::jsonb, 'Emily, you led the client interviews—would you share your view before we decide?', 'Calling on someone with relevant data invites inclusive participation.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which phrase transitions smoothly between agenda items?', '[{"label": "Next.", "value": "Next."}, {"label": "With budget updates covered, let''s move to the customer escalation status.", "value": "With budget updates covered, let''s move to the customer escalation status."}, {"label": "Ok done.", "value": "Ok done."}, {"label": "Whatever.", "value": "Whatever."}]'::jsonb, 'With budget updates covered, let''s move to the customer escalation status.', 'Transitions should reference what finished and what comes next.', 'BEC Vantage', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'How do you note an action item live during the meeting?', '[{"label": "Noted.", "value": "Noted."}, {"label": "I''ll record that action: IT to deliver the access audit by Wednesday.", "value": "I''ll record that action: IT to deliver the access audit by Wednesday."}, {"label": "Later.", "value": "Later."}, {"label": "Someone do it.", "value": "Someone do it."}]'::jsonb, 'I''ll record that action: IT to deliver the access audit by Wednesday.', 'Action logging should capture owner plus deadline for accountability.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which sentence best handles an agenda item that lacks data?', '[{"label": "Skip.", "value": "Skip."}, {"label": "Since we don''t have the updated churn numbers, let''s park this topic and revisit tomorrow after analytics shares the file.", "value": "Since we don''t have the updated churn numbers, let''s park this topic and revisit tomorrow after analytics shares the file."}, {"label": "Guess.", "value": "Guess."}, {"label": "No idea.", "value": "No idea."}]'::jsonb, 'Since we don''t have the updated churn numbers, let''s park this topic and revisit tomorrow after analytics shares the file.', 'Acknowledging missing data and scheduling a follow-up keeps the meeting productive.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Choose the best statement to clarify a complex slide.', '[{"label": "Look at this.", "value": "Look at this."}, {"label": "Let me highlight the three metrics on this slide: pipeline velocity, conversion, and deal size.", "value": "Let me highlight the three metrics on this slide: pipeline velocity, conversion, and deal size."}, {"label": "Pretty self-explanatory.", "value": "Pretty self-explanatory."}, {"label": "Numbers show the thing.", "value": "Numbers show the thing."}]'::jsonb, 'Let me highlight the three metrics on this slide: pipeline velocity, conversion, and deal size.', 'Guiding the audience through the structure aids comprehension.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which phrase politely requests that participants mute themselves?', '[{"label": "Mute please.", "value": "Mute please."}, {"label": "Could everyone mute when not speaking so we can hear the presenter clearly?", "value": "Could everyone mute when not speaking so we can hear the presenter clearly?"}, {"label": "Quiet.", "value": "Quiet."}, {"label": "Stop talking.", "value": "Stop talking."}]'::jsonb, 'Could everyone mute when not speaking so we can hear the presenter clearly?', 'Virtual etiquette requests should explain the benefit.', 'BEC Vantage', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'Identify the most diplomatic way to challenge a data source in a meeting.', '[{"label": "Your data is wrong.", "value": "Your data is wrong."}, {"label": "Just to be sure, is this churn number pulled from the latest CRM export or last quarter''s snapshot?", "value": "Just to be sure, is this churn number pulled from the latest CRM export or last quarter''s snapshot?"}, {"label": "Nope.", "value": "Nope."}, {"label": "Can''t trust that.", "value": "Can''t trust that."}]'::jsonb, 'Just to be sure, is this churn number pulled from the latest CRM export or last quarter''s snapshot?', 'Asking clarifying questions invites verification without confrontation.', 'BEC Vantage', 'hard', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which closing sentence best signals next steps and gratitude?', '[{"label": "Finish.", "value": "Finish."}, {"label": "Thanks for the candid input—I''ll circulate minutes and owners within the hour so we keep momentum.", "value": "Thanks for the candid input—I''ll circulate minutes and owners within the hour so we keep momentum."}, {"label": "Bye.", "value": "Bye."}, {"label": "Done here.", "value": "Done here."}]'::jsonb, 'Thanks for the candid input—I''ll circulate minutes and owners within the hour so we keep momentum.', 'Effective closings combine appreciation with an immediate action.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which sentence frames a concession as a trade-off?', '[{"label": "Fine, we will discount everything.", "value": "Fine, we will discount everything."}, {"label": "If we extend payment terms to 45 days, could you increase the minimum monthly volume by 20%?", "value": "If we extend payment terms to 45 days, could you increase the minimum monthly volume by 20%?"}, {"label": "Take it or leave it.", "value": "Take it or leave it."}, {"label": "You win.", "value": "You win."}]'::jsonb, 'If we extend payment terms to 45 days, could you increase the minimum monthly volume by 20%?', 'Linking a concession to a reciprocal commitment keeps leverage balanced.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Choose the best phrase to postpone a decision while gathering data.', '[{"label": "Not now.", "value": "Not now."}, {"label": "Could we revisit this clause tomorrow after our legal team shares the risk assessment?", "value": "Could we revisit this clause tomorrow after our legal team shares the risk assessment?"}, {"label": "Maybe later.", "value": "Maybe later."}, {"label": "We will see.", "value": "We will see."}]'::jsonb, 'Could we revisit this clause tomorrow after our legal team shares the risk assessment?', 'Providing a reason and concrete timeframe maintains trust.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which sentence respectfully challenges a customer''s demand?', '[{"label": "Impossible.", "value": "Impossible."}, {"label": "Help me understand how the 50% discount aligns with the scope expansion you just described.", "value": "Help me understand how the 50% discount aligns with the scope expansion you just described."}, {"label": "No.", "value": "No."}, {"label": "Forget it.", "value": "Forget it."}]'::jsonb, 'Help me understand how the 50% discount aligns with the scope expansion you just described.', 'Asking for rationale reframes the discussion with facts.', 'BEC Vantage', 'hard', 'approved', 'published'),
    ('level_test', 'single_choice', 'Identify the best sentence to highlight unique value instead of price.', '[{"label": "It''s expensive because it is.", "value": "It''s expensive because it is."}, {"label": "Our proposal includes on-site training and a dedicated analyst, which reduced churn by 18% for peers—shall we walk through that case study?", "value": "Our proposal includes on-site training and a dedicated analyst, which reduced churn by 18% for peers—shall we walk through that case study?"}, {"label": "Trust us.", "value": "Trust us."}, {"label": "You get what you pay for.", "value": "You get what you pay for."}]'::jsonb, 'Our proposal includes on-site training and a dedicated analyst, which reduced churn by 18% for peers—shall we walk through that case study?', 'Value selling uses evidence and engages the buyer.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which phrase signals a desire for a win-win outcome?', '[{"label": "Take it or leave it.", "value": "Take it or leave it."}, {"label": "Let''s explore a package that protects your budget while keeping our delivery timeline realistic.", "value": "Let''s explore a package that protects your budget while keeping our delivery timeline realistic."}, {"label": "Our way.", "value": "Our way."}, {"label": "We don''t compromise.", "value": "We don''t compromise."}]'::jsonb, 'Let''s explore a package that protects your budget while keeping our delivery timeline realistic.', 'Collaborative language recognizes both parties'' goals.', 'BEC Vantage', 'easy', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which statement best summarizes next steps after agreeing on principle?', '[{"label": "Ok bye.", "value": "Ok bye."}, {"label": "Great—we''ll draft the revised SOW and send it for your legal review by Thursday.", "value": "Great—we''ll draft the revised SOW and send it for your legal review by Thursday."}, {"label": "Done.", "value": "Done."}, {"label": "Later.", "value": "Later."}]'::jsonb, 'Great—we''ll draft the revised SOW and send it for your legal review by Thursday.', 'Negotiations end with precise follow-up actions.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which sentence politely asks for executive approval on the buyer''s side?', '[{"label": "Call your boss.", "value": "Call your boss."}, {"label": "Would it help if we prepared a summary for your CFO so they can approve the extended contract this week?", "value": "Would it help if we prepared a summary for your CFO so they can approve the extended contract this week?"}, {"label": "Talk upstairs.", "value": "Talk upstairs."}, {"label": "We need signatures now.", "value": "We need signatures now."}]'::jsonb, 'Would it help if we prepared a summary for your CFO so they can approve the extended contract this week?', 'Offering support for stakeholder alignment keeps momentum.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Choose the best language to de-escalate tension over penalties.', '[{"label": "Penalties stay.", "value": "Penalties stay."}, {"label": "I hear your concern about penalties—what if we cap them at 10% and add a monthly performance review so issues surface early?", "value": "I hear your concern about penalties—what if we cap them at 10% and add a monthly performance review so issues surface early?"}, {"label": "Too bad.", "value": "Too bad."}, {"label": "Deal with it.", "value": "Deal with it."}]'::jsonb, 'I hear your concern about penalties—what if we cap them at 10% and add a monthly performance review so issues surface early?', 'Acknowledging concerns and proposing safeguards calms the discussion.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which question uncovers hidden priorities?', '[{"label": "What else do you want?", "value": "What else do you want?"}, {"label": "Beyond price, which success metrics matter most for your stakeholders this quarter?", "value": "Beyond price, which success metrics matter most for your stakeholders this quarter?"}, {"label": "Anything more?", "value": "Anything more?"}, {"label": "Why?", "value": "Why?"}]'::jsonb, 'Beyond price, which success metrics matter most for your stakeholders this quarter?', 'Open questions reveal broader interests that can guide trade-offs.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which sentence signals you need internal approval before agreeing?', '[{"label": "Maybe.", "value": "Maybe."}, {"label": "Let me run this revised scope past our legal and finance teams—we can regroup tomorrow with a confirmed position.", "value": "Let me run this revised scope past our legal and finance teams—we can regroup tomorrow with a confirmed position."}, {"label": "I''ll get back whenever.", "value": "I''ll get back whenever."}, {"label": "No idea.", "value": "No idea."}]'::jsonb, 'Let me run this revised scope past our legal and finance teams—we can regroup tomorrow with a confirmed position.', 'Explain the internal process and timeframe to maintain credibility.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('level_test', 'single_choice', 'Select the most persuasive summary of benefits for a closing call.', '[{"label": "It''s good.", "value": "It''s good."}, {"label": "With the analytics add-on, your team gets same-day insights and a 25% faster forecast cycle—shall we schedule signing for Friday?", "value": "With the analytics add-on, your team gets same-day insights and a 25% faster forecast cycle—shall we schedule signing for Friday?"}, {"label": "Trust me.", "value": "Trust me."}, {"label": "You''ll like it.", "value": "You''ll like it."}]'::jsonb, 'With the analytics add-on, your team gets same-day insights and a 25% faster forecast cycle—shall we schedule signing for Friday?', 'Closing statements recap quantified value and propose a next step.', 'BEC Higher', 'hard', 'approved', 'published'),
    ('level_test', 'single_choice', 'Which response addresses a competitor comparison without discounting?', '[{"label": "They are worse.", "value": "They are worse."}, {"label": "I understand they offered a lower rate—our package includes 24/7 support and compliance tooling that saved others $400k annually; can we review those savings together?", "value": "I understand they offered a lower rate—our package includes 24/7 support and compliance tooling that saved others $400k annually; can we review those savings together?"}, {"label": "Ignore them.", "value": "Ignore them."}, {"label": "We are better.", "value": "We are better."}]'::jsonb, 'I understand they offered a lower rate—our package includes 24/7 support and compliance tooling that saved others $400k annually; can we review those savings together?', 'Comparisons should acknowledge competitors but refocus on differentiated value.', 'BEC Higher', 'hard', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which sentence is best for politely asking for an update?', '["Update me now", "Could you please share the latest progress update?", "Where is it?", "Tell me quickly"]'::jsonb, 'Could you please share the latest progress update?', 'Polite update requests are common in business communication.', 'BEC Preliminary', 'easy', 'approved', 'archived'),
    ('mock_exam', 'single_choice', 'Which response is most suitable when a client requests a discount?', '["No chance", "We can discuss volume-based pricing options", "Too expensive for you", "Not interested"]'::jsonb, 'We can discuss volume-based pricing options', 'This keeps the negotiation open and professional.', 'BEC Vantage', 'medium', 'approved', 'archived'),
    ('mock_exam', 'single_choice', 'Choose the strongest sentence for summarizing a proposal.', '["That is it", "In summary, this proposal reduces cost and improves delivery speed", "Okay done", "Please decide"]'::jsonb, 'In summary, this proposal reduces cost and improves delivery speed', 'A strong summary highlights value clearly.', 'BEC Higher', 'medium', 'approved', 'archived'),
    ('mock_exam', 'single_choice', 'Which reply best handles a client''s urgent shipment request?', '["Wait your turn", "We can prioritize production this week and share a revised delivery schedule tomorrow.", "Not possible", "Later"]'::jsonb, 'We can prioritize production this week and share a revised delivery schedule tomorrow.', 'It acknowledges urgency and offers a concrete plan.', 'BEC Vantage', 'medium', 'approved', 'archived'),
    ('mock_exam', 'single_choice', 'Choose the best statement to summarize market insight in a report.', '["Market is fine", "Customer data shows a 12% shift to premium bundles, so we should highlight value-add features in the launch deck.", "Everyone buys", "We guess"]'::jsonb, 'Customer data shows a 12% shift to premium bundles, so we should highlight value-add features in the launch deck.', 'It quantifies the trend and links it to an action.', 'BEC Higher', 'medium', 'approved', 'archived'),
    ('mock_exam', 'single_choice', 'Which negotiation move keeps the discussion collaborative?', '["Take it or leave it", "If we extend payment terms, could you increase the monthly volume commitment?", "Your problem", "We quit"]'::jsonb, 'If we extend payment terms, could you increase the monthly volume commitment?', 'It proposes a trade-off instead of a threat.', 'BEC Vantage', 'medium', 'approved', 'archived'),
    ('mock_exam', 'single_choice', 'Select the best follow-up after a steering committee decision.', '["Great", "Thank you for approving phase two. We will circulate the updated implementation roadmap by Friday.", "Cool", "Done"]'::jsonb, 'Thank you for approving phase two. We will circulate the updated implementation roadmap by Friday.', 'It acknowledges the decision and states a clear next step.', 'BEC Vantage', 'easy', 'approved', 'archived'),
    ('mock_exam', 'single_choice', 'Which sentence best communicates a risk mitigation plan to stakeholders?', '["Risk exists", "To mitigate the vendor outage, we have activated two backup suppliers and secured inventory for six weeks.", "Maybe fine", "Ignore it"]'::jsonb, 'To mitigate the vendor outage, we have activated two backup suppliers and secured inventory for six weeks.', 'It names the mitigation steps and timeframe.', 'BEC Higher', 'medium', 'approved', 'archived'),
    ('mock_exam', 'single_choice', 'Choose the strongest briefing update for leadership.', '["Working on it", "The pilot reduced support tickets by 28%, so we recommend rolling it out to APAC next month.", "Fine", "Ok"]'::jsonb, 'The pilot reduced support tickets by 28%, so we recommend rolling it out to APAC next month.', 'It shares data and a recommendation.', 'BEC Higher', 'medium', 'approved', 'archived'),
    ('mock_exam', 'single_choice', 'Which response best addresses a team''s workload concern?', '["Work faster", "Let us redistribute the client migrations so each pod handles three accounts instead of five.", "Too bad", "Deal with it"]'::jsonb, 'Let us redistribute the client migrations so each pod handles three accounts instead of five.', 'It proposes a concrete adjustment.', 'BEC Vantage', 'medium', 'approved', 'archived'),
    ('mock_exam', 'single_choice', 'Which reply best handles a customer complaint about onboarding speed?', '["Wait", "I understand the concern. We have assigned a dedicated specialist to complete the onboarding checklist by Wednesday.", "Cannot help", "Later"]'::jsonb, 'I understand the concern. We have assigned a dedicated specialist to complete the onboarding checklist by Wednesday.', 'It shows empathy plus a specific fix.', 'BEC Preliminary', 'medium', 'approved', 'archived'),
    ('mock_exam', 'single_choice', 'Select the best sentence for summarizing action items in meeting minutes.', '["Tasks noted", "Engineering will deliver the beta build on 18 April and sales will launch the customer webinar on 25 April.", "We all know", "Done"]'::jsonb, 'Engineering will deliver the beta build on 18 April and sales will launch the customer webinar on 25 April.', 'It clearly lists owners and deadlines.', 'BEC Preliminary', 'easy', 'approved', 'archived')
INSERT INTO question_content (module_type, question_type, stem, options_json, correct_answer, explanation, level, difficulty, review_status, publish_status)
VALUES
    ('mock_exam', 'single_choice', 'Which statement best communicates a phased rollout plan?', '["Roll out", "We will pilot with 50 enterprise customers in May, gather feedback for two weeks, then expand globally in June.", "Launch all", "Everyone now"]'::jsonb, 'We will pilot with 50 enterprise customers in May, gather feedback for two weeks, then expand globally in June.', 'It shows timing and next steps.', 'BEC Higher', 'medium', 'approved', 'archived'),
    ('mock_exam', 'single_choice', 'Which option best frames a commercial concession?', '["Discount given", "If you sign the three-year term, we can extend payment terms to 60 days and add premium support.", "Ok cheaper", "Take price"]'::jsonb, 'If you sign the three-year term, we can extend payment terms to 60 days and add premium support.', 'It trades concessions for commitment.', 'BEC Higher', 'medium', 'approved', 'archived'),
    ('mock_exam', 'single_choice', 'Which sentence best summarizes customer health for leadership?', '["Customers fine", "ARR retention is 94% but two strategic accounts need executive outreach due to integration delays.", "Ok", "All good"]'::jsonb, 'ARR retention is 94% but two strategic accounts need executive outreach due to integration delays.', 'It combines a metric with a call to action.', 'BEC Higher', 'medium', 'approved', 'archived'),
    ('mock_exam', 'single_choice', 'Which response best addresses an RFP clarification?', '["See spec", "Attached is the security architecture diagram plus the data encryption policy you requested.", "Later", "Use manual"]'::jsonb, 'Attached is the security architecture diagram plus the data encryption policy you requested.', 'It confirms delivery of the exact materials.', 'BEC Vantage', 'medium', 'approved', 'archived'),
    ('mock_exam', 'single_choice', 'What is the strongest wrap-up for a quarterly business review?', '["Thanks", "To close, we agreed on three priorities: stabilize onboarding, launch the upsell pilot, and review pricing in July.", "Bye", "That''s it"]'::jsonb, 'To close, we agreed on three priorities: stabilize onboarding, launch the upsell pilot, and review pricing in July.', 'It summarizes commitments and timing.', 'BEC Vantage', 'easy', 'approved', 'archived'),
    ('mock_exam', 'single_choice', 'Which sentence best explains a financial variance to the CFO?', '["Costs up", "Marketing costs exceeded plan by $180k because the APAC launch was pulled ahead by one quarter.", "Budget bad", "Too expensive"]'::jsonb, 'Marketing costs exceeded plan by $180k because the APAC launch was pulled ahead by one quarter.', 'It quantifies the variance and reason.', 'BEC Higher', 'medium', 'approved', 'archived'),
    ('mock_exam', 'single_choice', 'A client complains about onboarding speed. Which reply shows empathy plus action?', '[{"label": "Please wait.", "value": "Please wait."}, {"label": "I understand the delay is frustrating—we have assigned a dedicated specialist to complete your onboarding checklist by Wednesday.", "value": "I understand the delay is frustrating—we have assigned a dedicated specialist to complete your onboarding checklist by Wednesday."}, {"label": "Soon.", "value": "Soon."}, {"label": "Working on it.", "value": "Working on it."}]'::jsonb, 'I understand the delay is frustrating—we have assigned a dedicated specialist to complete your onboarding checklist by Wednesday.', 'Empathy plus a concrete fix resolves concerns faster.', 'BEC Preliminary', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which sentence best summarizes a quarterly business review action?', '[{"label": "Do tasks.", "value": "Do tasks."}, {"label": "Engineering will deliver the beta build on 18 April and sales will host the training webinar on 25 April.", "value": "Engineering will deliver the beta build on 18 April and sales will host the training webinar on 25 April."}, {"label": "Everyone knows.", "value": "Everyone knows."}, {"label": "Action later.", "value": "Action later."}]'::jsonb, 'Engineering will deliver the beta build on 18 April and sales will host the training webinar on 25 April.', 'Clear owners plus dates make the summary actionable.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Select the best update to reassure a customer about service levels.', '[{"label": "All good.", "value": "All good."}, {"label": "We added a weekend on-call engineer so your incidents receive responses within 30 minutes.", "value": "We added a weekend on-call engineer so your incidents receive responses within 30 minutes."}, {"label": "Trust us.", "value": "Trust us."}, {"label": "We try.", "value": "We try."}]'::jsonb, 'We added a weekend on-call engineer so your incidents receive responses within 30 minutes.', 'Service assurances should specify the change and expected benefit.', 'BEC Preliminary', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which reply handles a sudden discount demand diplomatically?', '[{"label": "No way.", "value": "No way."}, {"label": "Let''s review the scope change together—if we adjust the timeline, we can explore flexibility on the fee.", "value": "Let''s review the scope change together—if we adjust the timeline, we can explore flexibility on the fee."}, {"label": "Stop asking.", "value": "Stop asking."}, {"label": "Impossible.", "value": "Impossible."}]'::jsonb, 'Let''s review the scope change together—if we adjust the timeline, we can explore flexibility on the fee.', 'Counteroffers should reference scope and propose a structured trade-off.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which update requests feedback on a pilot politely?', '[{"label": "Thoughts?", "value": "Thoughts?"}, {"label": "Could you share any findings from last week''s pilot so we can capture them in the rollout plan?", "value": "Could you share any findings from last week''s pilot so we can capture them in the rollout plan?"}, {"label": "Need comments.", "value": "Need comments."}, {"label": "Tell me now.", "value": "Tell me now."}]'::jsonb, 'Could you share any findings from last week''s pilot so we can capture them in the rollout plan?', 'Specific prompts connect feedback to the next deliverable.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which line best communicates a service credit offer?', '[{"label": "We''ll discount.", "value": "We''ll discount."}, {"label": "To make up for the outage, we''d like to offer a one-month service credit and schedule a health check next week.", "value": "To make up for the outage, we''d like to offer a one-month service credit and schedule a health check next week."}, {"label": "Fine, free month.", "value": "Fine, free month."}, {"label": "Take credit.", "value": "Take credit."}]'::jsonb, 'To make up for the outage, we''d like to offer a one-month service credit and schedule a health check next week.', 'Pairing compensation with proactive follow-up restores trust.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which statement keeps executive stakeholders informed about adoption?', '[{"label": "Users like it.", "value": "Users like it."}, {"label": "Thirty branch managers activated the workflow in week one, generating 200 automated approvals—we''ll share detailed analytics Friday.", "value": "Thirty branch managers activated the workflow in week one, generating 200 automated approvals—we''ll share detailed analytics Friday."}, {"label": "Good usage.", "value": "Good usage."}, {"label": "People using.", "value": "People using."}]'::jsonb, 'Thirty branch managers activated the workflow in week one, generating 200 automated approvals—we''ll share detailed analytics Friday.', 'Executive updates should quantify adoption and promise next data drops.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which response addresses an escalation about missing features?', '[{"label": "Working on it.", "value": "Working on it."}, {"label": "You''re right that the export is delayed—product is releasing the patch Tuesday, and we''ll send you a preview build tomorrow.", "value": "You''re right that the export is delayed—product is releasing the patch Tuesday, and we''ll send you a preview build tomorrow."}, {"label": "Soon maybe.", "value": "Soon maybe."}, {"label": "Can''t do.", "value": "Can''t do."}]'::jsonb, 'You''re right that the export is delayed—product is releasing the patch Tuesday, and we''ll send you a preview build tomorrow.', 'Acknowledging the issue and sharing the timeline diffuses tension.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which line is best for closing a renewal conversation?', '[{"label": "Renew please.", "value": "Renew please."}, {"label": "With the analytics add-on generating 18% faster forecasts, shall we extend the agreement through 2028 so you lock pricing?", "value": "With the analytics add-on generating 18% faster forecasts, shall we extend the agreement through 2028 so you lock pricing?"}, {"label": "Need answer.", "value": "Need answer."}, {"label": "Sign now.", "value": "Sign now."}]'::jsonb, 'With the analytics add-on generating 18% faster forecasts, shall we extend the agreement through 2028 so you lock pricing?', 'Closing statements recap value and propose a concrete next step.', 'BEC Higher', 'hard', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which message sets expectations for a weekly check-in?', '[{"label": "Talk weekly.", "value": "Talk weekly."}, {"label": "Let''s touch base every Thursday to review KPIs and capture any blockers—I''ll send an invite.", "value": "Let''s touch base every Thursday to review KPIs and capture any blockers—I''ll send an invite."}, {"label": "Maybe meeting.", "value": "Maybe meeting."}, {"label": "We''ll see.", "value": "We''ll see."}]'::jsonb, 'Let''s touch base every Thursday to review KPIs and capture any blockers—I''ll send an invite.', 'Suggesting cadence + topics makes the meeting purposeful.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which line requests a reference quote politely?', '[{"label": "Say something good.", "value": "Say something good."}, {"label": "Would you be open to a short quote about your launch experience for our upcoming press release?", "value": "Would you be open to a short quote about your launch experience for our upcoming press release?"}, {"label": "Need testimonial.", "value": "Need testimonial."}, {"label": "Help marketing.", "value": "Help marketing."}]'::jsonb, 'Would you be open to a short quote about your launch experience for our upcoming press release?', 'Respectful asks explain the context and remain optional.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which sentence clarifies who owns a backlog item after a customer workshop?', '[{"label": "We''ll see.", "value": "We''ll see."}, {"label": "Product Ops will scope the workflow request this sprint and update you during Tuesday''s sync.", "value": "Product Ops will scope the workflow request this sprint and update you during Tuesday''s sync."}, {"label": "Someone handles it.", "value": "Someone handles it."}, {"label": "Soon.", "value": "Soon."}]'::jsonb, 'Product Ops will scope the workflow request this sprint and update you during Tuesday''s sync.', 'Customers expect to know owner and timing for open asks.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Your project is two weeks behind due to vendor delays. Which update balances transparency and control?', '[{"label": "We''re late.", "value": "We''re late."}, {"label": "Vendor tooling is two weeks behind; we escalated to their GM and activated a backup supplier, so launch stays on 12 May.", "value": "Vendor tooling is two weeks behind; we escalated to their GM and activated a backup supplier, so launch stays on 12 May."}, {"label": "Delay happening.", "value": "Delay happening."}, {"label": "Problems exist.", "value": "Problems exist."}]'::jsonb, 'Vendor tooling is two weeks behind; we escalated to their GM and activated a backup supplier, so launch stays on 12 May.', 'Pairing the issue with mitigation reassures sponsors.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which line clarifies critical path ownership?', '[{"label": "Ops handles it.", "value": "Ops handles it."}, {"label": "Ops will deliver the integration build by the 24th so QA can start environment testing on the 25th.", "value": "Ops will deliver the integration build by the 24th so QA can start environment testing on the 25th."}, {"label": "Team will do it.", "value": "Team will do it."}, {"label": "Pending.", "value": "Pending."}]'::jsonb, 'Ops will deliver the integration build by the 24th so QA can start environment testing on the 25th.', 'Explicit dependencies prevent surprises.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which sentence best requests a steering committee decision?', '[{"label": "Need answer.", "value": "Need answer."}, {"label": "We need guidance: do we prioritize the LATAM localization for July or keep the AI pilot on track for August?", "value": "We need guidance: do we prioritize the LATAM localization for July or keep the AI pilot on track for August?"}, {"label": "Tell us now.", "value": "Tell us now."}, {"label": "Decide.", "value": "Decide."}]'::jsonb, 'We need guidance: do we prioritize the LATAM localization for July or keep the AI pilot on track for August?', 'Frame decisions as trade-offs with context so executives can respond quickly.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which update shows proactive risk management?', '[{"label": "Risk noted.", "value": "Risk noted."}, {"label": "To mitigate the data-center outage risk, we''ve mirrored workloads to region B and scheduled failover drills every Friday.", "value": "To mitigate the data-center outage risk, we''ve mirrored workloads to region B and scheduled failover drills every Friday."}, {"label": "We''ll watch it.", "value": "We''ll watch it."}, {"label": "Hope it''s fine.", "value": "Hope it''s fine."}]'::jsonb, 'To mitigate the data-center outage risk, we''ve mirrored workloads to region B and scheduled failover drills every Friday.', 'Detailed mitigation steps signal control.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which status message quantifies progress?', '[{"label": "Almost done.", "value": "Almost done."}, {"label": "Sprint 9 delivered 14 story points, keeping us 3% ahead of plan.", "value": "Sprint 9 delivered 14 story points, keeping us 3% ahead of plan."}, {"label": "On track.", "value": "On track."}, {"label": "Working.", "value": "Working."}]'::jsonb, 'Sprint 9 delivered 14 story points, keeping us 3% ahead of plan.', 'Stakeholders expect numbers, not vague adjectives.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which phrase politely pushes back on scope creep?', '[{"label": "Can''t add that.", "value": "Can''t add that."}, {"label": "To add the chatbot, we''d need to extend the timeline by two weeks or drop the analytics dashboard—how would you like to proceed?", "value": "To add the chatbot, we''d need to extend the timeline by two weeks or drop the analytics dashboard—how would you like to proceed?"}, {"label": "No new scope.", "value": "No new scope."}, {"label": "Stop changing things.", "value": "Stop changing things."}]'::jsonb, 'To add the chatbot, we''d need to extend the timeline by two weeks or drop the analytics dashboard—how would you like to proceed?', 'Offer options with trade-offs rather than flat refusals.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which sentence keeps executives informed about pilot KPIs?', '[{"label": "Pilot good.", "value": "Pilot good."}, {"label": "The pilot cut ticket backlog by 32% and we plan to scale to APAC once we hit 40% sustained reduction.", "value": "The pilot cut ticket backlog by 32% and we plan to scale to APAC once we hit 40% sustained reduction."}, {"label": "Nice results.", "value": "Nice results."}, {"label": "Going ok.", "value": "Going ok."}]'::jsonb, 'The pilot cut ticket backlog by 32% and we plan to scale to APAC once we hit 40% sustained reduction.', 'Tie results to next milestones.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which update ensures cross-team alignment?', '[{"label": "All teams informed.", "value": "All teams informed."}, {"label": "Marketing, Legal, and Support synced today—shared launch tracker is in Confluence for real-time status.", "value": "Marketing, Legal, and Support synced today—shared launch tracker is in Confluence for real-time status."}, {"label": "Hope everyone knows.", "value": "Hope everyone knows."}, {"label": "Tell others.", "value": "Tell others."}]'::jsonb, 'Marketing, Legal, and Support synced today—shared launch tracker is in Confluence for real-time status.', 'Name groups and artifacts to show coordination.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which question surfaces dependencies early?', '[{"label": "Anything else?", "value": "Anything else?"}, {"label": "Are there any vendor approvals that could block your component before code freeze next Friday?", "value": "Are there any vendor approvals that could block your component before code freeze next Friday?"}, {"label": "Stuff pending?", "value": "Stuff pending?"}, {"label": "All clear?", "value": "All clear?"}]'::jsonb, 'Are there any vendor approvals that could block your component before code freeze next Friday?', 'Targeted questions uncover issues proactively.', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which statement captures lessons learned constructively?', '[{"label": "We failed.", "value": "We failed."}, {"label": "Key lesson: pair QA engineers with analysts during UAT to catch data issues earlier—we''ll apply this in Phase 2.", "value": "Key lesson: pair QA engineers with analysts during UAT to catch data issues earlier—we''ll apply this in Phase 2."}, {"label": "Lots went wrong.", "value": "Lots went wrong."}, {"label": "Bad process.", "value": "Bad process."}]'::jsonb, 'Key lesson: pair QA engineers with analysts during UAT to catch data issues earlier—we''ll apply this in Phase 2.', 'Lessons should include the future action.', 'BEC Higher', 'hard', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which request secures additional budget with justification?', '[{"label": "Need more money.", "value": "Need more money."}, {"label": "To meet the client-mandated compliance update, we need $120k for a dedicated audit squad; otherwise go-live slips by six weeks.", "value": "To meet the client-mandated compliance update, we need $120k for a dedicated audit squad; otherwise go-live slips by six weeks."}, {"label": "Give funds.", "value": "Give funds."}, {"label": "Budget please.", "value": "Budget please."}]'::jsonb, 'To meet the client-mandated compliance update, we need $120k for a dedicated audit squad; otherwise go-live slips by six weeks.', 'Budget requests must tie spend to risk avoidance.', 'BEC Higher', 'hard', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which update informs stakeholders about training readiness?', '[{"label": "Training soon.", "value": "Training soon."}, {"label": "All facilitators completed certification and training decks are ready for next Monday''s dry run.", "value": "All facilitators completed certification and training decks are ready for next Monday''s dry run."}, {"label": "Working on training.", "value": "Working on training."}, {"label": "Almost set.", "value": "Almost set."}]'::jsonb, 'All facilitators completed certification and training decks are ready for next Monday''s dry run.', 'Readiness updates should confirm prerequisites are met.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which statement communicates a currency risk hedge to stakeholders?', '[{"label": "FX is risky.", "value": "FX is risky."}, {"label": "We''ve hedged 80% of EUR exposure for Q3, limiting downside to $200k even if the euro drops another 5%.", "value": "We''ve hedged 80% of EUR exposure for Q3, limiting downside to $200k even if the euro drops another 5%."}, {"label": "Watching FX.", "value": "Watching FX."}, {"label": "Not sure.", "value": "Not sure."}]'::jsonb, 'We''ve hedged 80% of EUR exposure for Q3, limiting downside to $200k even if the euro drops another 5%.', 'Quantify coverage and residual risk.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which line summarizes compliance remediation clearly?', '[{"label": "We fixed issues.", "value": "We fixed issues."}, {"label": "Audit findings 3 and 4 are closed: access reviews run monthly and evidence was uploaded to GRC.", "value": "Audit findings 3 and 4 are closed: access reviews run monthly and evidence was uploaded to GRC."}, {"label": "Compliance ok.", "value": "Compliance ok."}, {"label": "Done.", "value": "Done."}]'::jsonb, 'Audit findings 3 and 4 are closed: access reviews run monthly and evidence was uploaded to GRC.', 'Executives expect reference to control owners and evidence.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which sentence requests finance approval responsibly?', '[{"label": "Sign this.", "value": "Sign this."}, {"label": "Could you approve the $450k capex this week? Delays push back savings from the automation program by a quarter.", "value": "Could you approve the $450k capex this week? Delays push back savings from the automation program by a quarter."}, {"label": "Need sign.", "value": "Need sign."}, {"label": "Please approve.", "value": "Please approve."}]'::jsonb, 'Could you approve the $450k capex this week? Delays push back savings from the automation program by a quarter.', 'Include urgency plus impact.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which update reassures leadership about cost controls?', '[{"label": "Costs stable.", "value": "Costs stable."}, {"label": "Travel spend is down 18% after the new approval workflow; we''ll monitor monthly to maintain compliance.", "value": "Travel spend is down 18% after the new approval workflow; we''ll monitor monthly to maintain compliance."}, {"label": "Budget fine.", "value": "Budget fine."}, {"label": "Ok.", "value": "Ok."}]'::jsonb, 'Travel spend is down 18% after the new approval workflow; we''ll monitor monthly to maintain compliance.', 'Tie results to the control mechanism and ongoing monitoring.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which sentence explains working-capital stress concisely?', '[{"label": "Cash tight.", "value": "Cash tight."}, {"label": "Receivables are 12 days slower due to the ERP cutover; without acceleration, we breach covenants in July.", "value": "Receivables are 12 days slower due to the ERP cutover; without acceleration, we breach covenants in July."}, {"label": "Need cash.", "value": "Need cash."}, {"label": "Collections bad.", "value": "Collections bad."}]'::jsonb, 'Receivables are 12 days slower due to the ERP cutover; without acceleration, we breach covenants in July.', 'State cause, metric, and consequence.', 'BEC Higher', 'hard', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which message frames insurance coverage adjustments?', '[{"label": "Insurance change.", "value": "Insurance change."}, {"label": "We raised cyber coverage to $50M and added breach response riders to meet customer contract terms.", "value": "We raised cyber coverage to $50M and added breach response riders to meet customer contract terms."}, {"label": "Updated policy.", "value": "Updated policy."}, {"label": "Insurance fine.", "value": "Insurance fine."}]'::jsonb, 'We raised cyber coverage to $50M and added breach response riders to meet customer contract terms.', 'Mention new limits and the driver.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which response addresses internal audit concerns constructively?', '[{"label": "Noted.", "value": "Noted."}, {"label": "We''ll deploy segregation-of-duty monitoring next sprint and deliver evidence before the follow-up audit on 30 May.", "value": "We''ll deploy segregation-of-duty monitoring next sprint and deliver evidence before the follow-up audit on 30 May."}, {"label": "Later.", "value": "Later."}, {"label": "Okay.", "value": "Okay."}]'::jsonb, 'We''ll deploy segregation-of-duty monitoring next sprint and deliver evidence before the follow-up audit on 30 May.', 'Audit responses require timelines and artifacts.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which sentence escalates a fraud signal properly?', '[{"label": "Fraud maybe.", "value": "Fraud maybe."}, {"label": "Unusual refunds from region West exceed thresholds—we need Risk to freeze the channel until forensics reviews the logs tomorrow.", "value": "Unusual refunds from region West exceed thresholds—we need Risk to freeze the channel until forensics reviews the logs tomorrow."}, {"label": "Weird things.", "value": "Weird things."}, {"label": "Investigate?", "value": "Investigate?"}]'::jsonb, 'Unusual refunds from region West exceed thresholds—we need Risk to freeze the channel until forensics reviews the logs tomorrow.', 'Escalations must cite thresholds and required action.', 'BEC Higher', 'hard', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which update highlights treasury''s liquidity actions?', '[{"label": "Liquidity ok.", "value": "Liquidity ok."}, {"label": "We extended our revolver to 2029 and added $50M in unused capacity to cushion macro volatility.", "value": "We extended our revolver to 2029 and added $50M in unused capacity to cushion macro volatility."}, {"label": "Cash fine.", "value": "Cash fine."}, {"label": "Plenty of funds.", "value": "Plenty of funds."}]'::jsonb, 'We extended our revolver to 2029 and added $50M in unused capacity to cushion macro volatility.', 'Spell out instruments, amounts, and rationale.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which sentence requests board approval for a divestiture succinctly?', '[{"label": "Sell unit.", "value": "Sell unit."}, {"label": "We recommend divesting the legacy hardware unit for $70M, freeing capital for SaaS expansion and lifting gross margin by 4 pts.", "value": "We recommend divesting the legacy hardware unit for $70M, freeing capital for SaaS expansion and lifting gross margin by 4 pts."}, {"label": "Need to sell.", "value": "Need to sell."}, {"label": "Approve sale.", "value": "Approve sale."}]'::jsonb, 'We recommend divesting the legacy hardware unit for $70M, freeing capital for SaaS expansion and lifting gross margin by 4 pts.', 'Board proposals should highlight proceeds and strategic benefit.', 'BEC Higher', 'hard', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which summary best links market data to a recommendation?', '[{"label": "Market is fine.", "value": "Market is fine."}, {"label": "Premium bundles grew 12% YoY; shifting launch messaging to value-add services should defend margin.", "value": "Premium bundles grew 12% YoY; shifting launch messaging to value-add services should defend margin."}, {"label": "Sales ok.", "value": "Sales ok."}, {"label": "Customers like it.", "value": "Customers like it."}]'::jsonb, 'Premium bundles grew 12% YoY; shifting launch messaging to value-add services should defend margin.', 'Strategies must tie data to action.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which line frames strategic options clearly?', '[{"label": "We need a plan.", "value": "We need a plan."}, {"label": "Option A accelerates product launches but requires $3M capex; Option B protects cash but delays AI features by two quarters.", "value": "Option A accelerates product launches but requires $3M capex; Option B protects cash but delays AI features by two quarters."}, {"label": "Multiple choices.", "value": "Multiple choices."}, {"label": "Either way.", "value": "Either way."}]'::jsonb, 'Option A accelerates product launches but requires $3M capex; Option B protects cash but delays AI features by two quarters.', 'Decision slides should outline trade-offs explicitly.', 'BEC Higher', 'hard', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which statement requests executive sponsorship for cross-functional work?', '[{"label": "Need support.", "value": "Need support."}, {"label": "Could you co-sign the transformation brief so Legal, Ops, and Sales treat it as a Tier-1 initiative?", "value": "Could you co-sign the transformation brief so Legal, Ops, and Sales treat it as a Tier-1 initiative?"}, {"label": "Please help.", "value": "Please help."}, {"label": "Do this.", "value": "Do this."}]'::jsonb, 'Could you co-sign the transformation brief so Legal, Ops, and Sales treat it as a Tier-1 initiative?', 'State the ask plus impact on other teams.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which question uncovers competitive threats effectively?', '[{"label": "Competitors?", "value": "Competitors?"}, {"label": "Which competitor moves could disrupt our SMB share in the next six months?", "value": "Which competitor moves could disrupt our SMB share in the next six months?"}, {"label": "Any rivals?", "value": "Any rivals?"}, {"label": "Who cares?", "value": "Who cares?"}]'::jsonb, 'Which competitor moves could disrupt our SMB share in the next six months?', 'Specific timeframes and segments focus analysis.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which update explains how a strategy will be executed?', '[{"label": "We''ll execute.", "value": "We''ll execute."}, {"label": "We''ll pilot with 50 key accounts, measure retention uplift after one quarter, then scale globally if we hit 10% improvement.", "value": "We''ll pilot with 50 key accounts, measure retention uplift after one quarter, then scale globally if we hit 10% improvement."}, {"label": "Roll out soon.", "value": "Roll out soon."}, {"label": "Implement everywhere.", "value": "Implement everywhere."}]'::jsonb, 'We''ll pilot with 50 key accounts, measure retention uplift after one quarter, then scale globally if we hit 10% improvement.', 'Execution plans specify cohort, metric, and gate.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which sentence ties talent strategy to business goals?', '[{"label": "Hire more.", "value": "Hire more."}, {"label": "To support the fintech push, we need five senior solution architects—without them, deal velocity drops next quarter.", "value": "To support the fintech push, we need five senior solution architects—without them, deal velocity drops next quarter."}, {"label": "Need people.", "value": "Need people."}, {"label": "Staff shortage.", "value": "Staff shortage."}]'::jsonb, 'To support the fintech push, we need five senior solution architects—without them, deal velocity drops next quarter.', 'Talent requests should connect capabilities to outcomes.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which message secures alignment on customer segmentation?', '[{"label": "Segment change.", "value": "Segment change."}, {"label": "We''ll focus GTM on mid-market accounts with $20–50M revenue because they show 2x conversion—does anyone see issues with that focus?", "value": "We''ll focus GTM on mid-market accounts with $20–50M revenue because they show 2x conversion—does anyone see issues with that focus?"}, {"label": "Target mid.", "value": "Target mid."}, {"label": "New segment.", "value": "New segment."}]'::jsonb, 'We''ll focus GTM on mid-market accounts with $20–50M revenue because they show 2x conversion—does anyone see issues with that focus?', 'State the rationale and invite objection before finalizing.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which sentence escalates a strategic blocker appropriately?', '[{"label": "Blocked.", "value": "Blocked."}, {"label": "The partner data-sharing agreement is stalled—without your sponsorship, we risk missing the Q3 marketplace launch.", "value": "The partner data-sharing agreement is stalled—without your sponsorship, we risk missing the Q3 marketplace launch."}, {"label": "Problem.", "value": "Problem."}, {"label": "Need help.", "value": "Need help."}]'::jsonb, 'The partner data-sharing agreement is stalled—without your sponsorship, we risk missing the Q3 marketplace launch.', 'Escalations should show business impact and required action.', 'BEC Higher', 'hard', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which update best communicates OKR progress to leadership?', '[{"label": "OKRs good.", "value": "OKRs good."}, {"label": "Objective 1 is on track: 85% of prioritized workflows are automated and we''re heading for the 100% target by June.", "value": "Objective 1 is on track: 85% of prioritized workflows are automated and we''re heading for the 100% target by June."}, {"label": "Working.", "value": "Working."}, {"label": "Progress.", "value": "Progress."}]'::jsonb, 'Objective 1 is on track: 85% of prioritized workflows are automated and we''re heading for the 100% target by June.', 'Leaders need metrics plus forecast.', 'BEC Higher', 'medium', 'approved', 'published'),
    ('mock_exam', 'single_choice', 'Which line proposes a partnership evaluation effectively?', '[{"label": "Check partner.", "value": "Check partner."}, {"label": "Let''s evaluate a logistics partner to speed EU deliveries—we''ll compare costs and SLA impact by next steering session.", "value": "Let''s evaluate a logistics partner to speed EU deliveries—we''ll compare costs and SLA impact by next steering session."}, {"label": "Look into it.", "value": "Look into it."}, {"label": "Maybe partner.", "value": "Maybe partner."}]'::jsonb, 'Let''s evaluate a logistics partner to speed EU deliveries—we''ll compare costs and SLA impact by next steering session.', 'State goal, scope, and timeline when proposing analyses.', 'BEC Higher', 'medium', 'approved', 'published')
INSERT INTO scene_content (scene_name, scene_background, training_goal, user_role, ai_role, prompt_template, recommended_expression, level, difficulty, review_status, publish_status)
VALUES
    ('Project Kickoff Meeting', 'You are joining a kickoff meeting with a new overseas client to confirm timeline, responsibilities, and communication rules.', 'Practice opening a meeting, clarifying deliverables, and confirming next steps.', 'Project coordinator', 'Client representative', 'You are a professional overseas client representative. Hold a short kickoff discussion, ask about timeline and deliverables, and respond naturally in business English.', 'Could we align on the timeline?; Let us summarize the action items.; If I understand correctly, ...', 'BEC Vantage', 'medium', 'approved', 'published'),
    ('Shipment Delay Call', 'A customer is calling about a delayed shipment and expects a clear explanation plus a recovery plan.', 'Practice apologizing professionally, explaining delay reasons, and proposing solutions.', 'Account manager', 'Concerned customer', 'You are a concerned customer asking why the shipment is late and what compensation or solution is available.', 'We regret to inform you that ...; We are taking steps to resolve it.; Would it be possible to ...', 'BEC Higher', 'hard', 'approved', 'published'),
    ('Weekly Sales Update', 'You need to report weekly sales performance to your manager and highlight both progress and risks.', 'Practice giving a concise update, reporting numbers, and flagging issues.', 'Sales executive', 'Sales manager', 'You are a sales manager listening to an update. Ask follow-up questions about numbers, risks, and next actions.', 'I''d like to begin with ...; From our perspective, ...; Moving on to the next point.', 'BEC Preliminary', 'easy', 'approved', 'published'),
    ('Quarterly Business Review', 'You are hosting a QBR with a strategic client to discuss KPIs, risks, and next steps.', 'Practice presenting metrics, capturing client concerns, and aligning on actions.', 'Customer success manager', 'Client operations director', 'You are the client''s operations director attending a QBR. Ask for KPI clarity, probe about risks, and request concrete follow-ups.
